One workaround for the race is to serialize vfprintf() calls that use
floating point conversion specifications.


Index: stdio/vfprintf.c
===================================================================
RCS file: /home/ncvs/src/lib/libc/stdio/vfprintf.c,v
retrieving revision 1.23
diff -u -r1.23 vfprintf.c
--- stdio/vfprintf.c	2001/01/06 20:48:00	1.23
+++ stdio/vfprintf.c	2001/01/06 23:15:45
@@ -261,6 +261,17 @@
 #include <math.h>
 #include "floatio.h"

+/* 
+ * Serialize calls to cvt and __dtoa() and the usage of the result
+ * in threaded programs.
+ */
+
+#include "libc_private.h"
+#include "spinlock.h"
+static spinlock_t thread_lock	= _SPINLOCK_INITIALIZER;
+#define THREAD_LOCK()		if (__isthreaded) _SPINLOCK(&thread_lock);
+#define THREAD_UNLOCK()		if (__isthreaded) _SPINUNLOCK(&thread_lock);
+
 #define	BUF		(MAXEXP+MAXFRACT+1)	/* + decimal point */
 #define	DEFPREC		6

@@ -271,6 +282,9 @@

 #define	BUF		68

+#define THREAD_LOCK()
+#define THREAD_UNLOCK()
+
 #endif /* FLOATING_POINT */

 #define STATIC_ARG_TBL_SIZE 8           /* Size of static argument table. */
@@ -303,6 +317,7 @@
 	int width;		/* width from format (%8d), or 0 */
 	int prec;		/* precision from format (%.3d), or -1 */
 	char sign;		/* sign prefix (' ', '+', '-', or \0) */
+	int didlock;		/* have obtained thread lock */
 #ifdef FLOATING_POINT
 	char softsign;		/* temporary negative sign for floats */
 	double _double;		/* double precision arguments %[eEfgG] */
@@ -418,6 +433,7 @@
         }


+	didlock = 0;
 	FLOCKFILE(fp);
 	/* sorry, fprintf(read_only_file, "") returns EOF, not 0 */
 	if (cantwrite(fp)) {
@@ -608,6 +624,8 @@
 				break;
 			}
 			flags |= FPT;
+			THREAD_LOCK();
+			didlock = 1;
 			cp = cvt(_double, prec, flags, &softsign,
 				&expt, ch, &ndig);
 			if (ch == 'g' || ch == 'G') {
@@ -849,6 +867,10 @@
 					PRINT(cp, 1);
 				PRINT(expstr, expsize);
 			}
+			if (didlock != 0) {
+			  THREAD_UNLOCK();
+			  didlock = 0;
+			}
 		}
 #else
 		PRINT(cp, size);
@@ -865,6 +887,10 @@
 done:
 	FLUSH();
 error:
+	if (didlock != 0) {
+	  THREAD_UNLOCK();
+	  didlock = 0;
+	}
 	if (__sferror(fp))
 		ret = EOF;
 	FUNLOCKFILE(fp);
